import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as i,e as p}from"./app-d99acea3.js";const x={},t=p('<h1 id="nginx" tabindex="-1"><a class="header-anchor" href="#nginx" aria-hidden="true">#</a> Nginx</h1><p>Nginx:是一个高性能的HTTP和反向代理Web服务器，占用内存少，并发能力强，最高能支持5w的并发量。</p><p>正向代理：使用VPN访问外网，是代理客户端</p><p>Nginx有以下两个特点</p><p>反向代理:代理服务端</p><p>负载均衡:对大小不同的服务器有较好的平衡</p><p>注意事项：要把Nginx文件放到没有中文的路径下，默认端口号80</p><p>常用命令：</p><p>1.在nginx.exe文件路径下使用cmd，输入nginx.exe启动nginx</p><p>2.在nginx.exe文件路径下使用cmd，输入nginx -s stop停止nginx</p><p>3.在nginx.exe文件路径下使用cmd，输入nginx -s quit安全退出nginx</p><p>4.在nginx.exe文件路径下使用cmd，输入nginx -s reload重新加载配置文件</p><p>部署前端项目：将自己写的Html文件放到Nginx HTMl文件中去</p>',13),c=[t];function o(a,g){return e(),i("div",null,c)}const d=n(x,[["render",o],["__file","Nginx.html.vue"]]);export{d as default};
